// Receipt Entry API — บันทึกรับเรื่องงานทะเบียนแบบ manual
const body = ($input.first().json && $input.first().json.body) || $input.first().json || {};
const action = String(body.action || body.op || '').trim();
const esc = v => (v==null||v==='')?'NULL':"'"+String(v).replace(/'/g,"''")+"'";
const num = v => isFinite(Number(v)) ? Number(v) : 0;
const intOrNull = v => (v==null||v==='')?null:(parseInt(v,10)||null);
const d = v => v && /^\d{4}-\d{2}-\d{2}/.test(String(v)) ? `'${String(v).slice(0,10)}'::date` : 'NULL';
let query;

if (action === 'get_next_receipt_no') {
  // auto-gen: {BRANCH}-CA{YYMM}{NNNNN} → query MAX seq for branch + YYMM
  const branch = String(body.branch_code || 'SCY01').trim();
  const now = new Date();
  const beYY = String((now.getFullYear() + 543) % 100).padStart(2,'0');
  const mm = String(now.getMonth() + 1).padStart(2,'0');
  const ym = beYY + mm;
  const prefix = `${branch}-CA${ym}`;
  query = `WITH last_seq AS (
    SELECT COALESCE(MAX(CAST(SUBSTRING(receipt_no FROM '[0-9]{5}\\$') AS INTEGER)), 0) AS seq
    FROM registration_receipts
    WHERE receipt_no LIKE '${prefix}%'
  )
  SELECT '${prefix}' || LPAD((seq + 1)::text, 5, '0') AS next_receipt_no FROM last_seq;`;
  // ใช้ LIKE + SUBSTRING แทน regex เพราะ Postgres node mangle $ — ใส่ใน LIKE pattern OK
  // ปรับ: ใช้ LIKE matching ตำแหน่ง 5 ตัวสุดท้าย
  query = `WITH last_seq AS (
    SELECT COALESCE(MAX(CAST(RIGHT(receipt_no, 5) AS INTEGER)), 0) AS seq
      FROM registration_receipts
     WHERE receipt_no LIKE '${prefix}%'
       AND LENGTH(receipt_no) = ${prefix.length + 5}
       AND RIGHT(receipt_no, 5) !~ '[^0-9]'
  )
  SELECT '${prefix}' || LPAD((seq + 1)::text, 5, '0') AS next_receipt_no FROM last_seq;`;
}
else if (action === 'search_similar') {
  // ค้นใน 2 แหล่ง: moto_sales + registration_receipts — ทำเป็น UNION เพื่อให้รวมผลในคำสั่งเดียว
  const kw = String(body.keyword || '').trim();
  if (!kw) return [{ json: { query: "SELECT 'missing keyword' AS message" } }];
  const k = kw.toUpperCase().replace(/'/g, "''");
  query = `
    SELECT 'sale' AS source, s.id::text AS ref_id, s.invoice_no AS ref_no, s.sale_date AS ref_date,
      s.customer_name, s.address AS customer_address, s.customer_phone, s.id_card AS customer_id_card,
      s.chassis_no, s.engine_no, s.color_name AS color,
      s.brand, s.model_series, s.model_code, s.product_code,
      r.plate_number, s.finance_company AS contract_ref,
      NULL::text AS receipt_no, s.branch_code AS branch_code
    FROM moto_sales s
    LEFT JOIN moto_registrations r ON r.frame_no = s.chassis_no
    WHERE UPPER(s.chassis_no) LIKE '%${k}%'
       OR UPPER(s.engine_no) LIKE '%${k}%'
       OR UPPER(COALESCE(r.plate_number,'')) LIKE '%${k}%'
       OR UPPER(s.customer_name) LIKE '%${k}%'
       OR UPPER(s.invoice_no) LIKE '%${k}%'
    UNION ALL
    SELECT 'receipt' AS source, r.receipt_no AS ref_id, r.receipt_no AS ref_no, r.receive_date AS ref_date,
      r.customer_name, r.customer_address, r.customer_phone, r.customer_id_card,
      r.chassis_no, r.engine_no, r.color,
      r.brand, r.model_series, r.model_code, r.product_code,
      r.plate_number, r.contract_ref,
      r.receipt_no, r.branch_code
    FROM registration_receipts r
    WHERE UPPER(COALESCE(r.chassis_no,'')) LIKE '%${k}%'
       OR UPPER(COALESCE(r.engine_no,'')) LIKE '%${k}%'
       OR UPPER(COALESCE(r.plate_number,'')) LIKE '%${k}%'
       OR UPPER(COALESCE(r.customer_name,'')) LIKE '%${k}%'
    ORDER BY ref_date DESC NULLS LAST
    LIMIT 30;`;
}
else if (action === 'lookup_sale') {
  // ค้น moto_sales จาก chassis_no หรือ engine_no
  const chassis = String(body.chassis_no || '').trim();
  const engine = String(body.engine_no || '').trim();
  if (!chassis && !engine) return [{ json: { query: "SELECT 'missing chassis_no or engine_no' AS message" } }];
  const wh = [];
  if (chassis) wh.push(`UPPER(s.chassis_no) = UPPER(${esc(chassis)})`);
  if (engine) wh.push(`UPPER(s.engine_no) = UPPER(${esc(engine)})`);
  query = `SELECT s.id AS sale_id, s.invoice_no AS sale_invoice_no, s.sale_date,
      s.customer_name, s.address AS customer_address, s.customer_phone, s.id_card AS customer_id_card,
      s.chassis_no, s.engine_no, s.color_name AS color,
      s.brand, s.model_series, s.model_code, s.product_code,
      r.plate_number, s.finance_company AS contract_ref
    FROM moto_sales s
    LEFT JOIN moto_registrations r ON r.frame_no = s.chassis_no
   WHERE ${wh.join(' OR ')}
   ORDER BY s.sale_date DESC LIMIT 1;`;
}
else if (action === 'list_receipts') {
  // รายการที่บันทึก manual (filter ทั่วไป)
  const wh = [];
  if (body.branch_code) wh.push(`r.branch_code = ${esc(body.branch_code)}`);
  if (body.date_from) wh.push(`r.receive_date >= ${d(body.date_from)}`);
  if (body.date_to) wh.push(`r.receive_date <= ${d(body.date_to)}`);
  if (body.keyword) {
    const kw = esc('%' + body.keyword + '%');
    wh.push(`(UPPER(r.receipt_no) LIKE UPPER(${kw}) OR UPPER(r.chassis_no) LIKE UPPER(${kw}) OR UPPER(r.engine_no) LIKE UPPER(${kw}) OR UPPER(r.customer_name) LIKE UPPER(${kw}))`);
  }
  // เฉพาะที่บันทึก manual: marker = receipt_status = 'manual' หรือ note LIKE 'MANUAL%' หรือเอาทั้งหมด
  if (body.only_manual) wh.push(`r.entry_source = 'manual'`);
  const where = wh.length ? ('WHERE ' + wh.join(' AND ')) : '';
  query = `SELECT r.*, (
      SELECT COALESCE(SUM(net_price), 0)
        FROM registration_receipt_lines l WHERE l.receipt_no = r.receipt_no
    ) AS line_total,
    (SELECT COUNT(*) FROM registration_receipt_lines l WHERE l.receipt_no = r.receipt_no) AS line_count
    FROM registration_receipts r
    ${where}
    ORDER BY r.receive_date DESC, r.receipt_no DESC LIMIT 1000;`;
}
else if (action === 'get_receipt') {
  const rno = String(body.receipt_no || '').trim();
  if (!rno) return [{ json: { query: "SELECT 'missing receipt_no' AS message" } }];
  query = `SELECT json_build_object(
      'header', (SELECT row_to_json(r) FROM registration_receipts r WHERE r.receipt_no = ${esc(rno)}),
      'lines',  (SELECT COALESCE(json_agg(l ORDER BY l.id), '[]'::json) FROM registration_receipt_lines l WHERE l.receipt_no = ${esc(rno)})
    ) AS data;`;
}
else if (action === 'save_receipt') {
  // body: { receipt_no, ...header_fields, lines: [{income_type, income_code, income_name, description, qty, price, discount}] }
  const h = body.header || body;
  const lines = Array.isArray(body.lines) ? body.lines : [];
  const rno = String(h.receipt_no || '').trim();
  if (!rno) return [{ json: { query: "SELECT 'missing receipt_no' AS message" } }];
  if (lines.length === 0) return [{ json: { query: "SELECT 'no line items' AS message" } }];
  // total
  let lineTotal = 0;
  for (const ln of lines) {
    const q = num(ln.qty || 1);
    const p = num(ln.price_before_discount ?? ln.price ?? 0);
    const dc = num(ln.discount || 0);
    const net = q * p - dc;
    ln._net = net;
    lineTotal += net;
  }
  const vatRate = num(h.vat_rate || 0);
  const priceBeforeVat = vatRate > 0 ? lineTotal / (1 + vatRate/100) : lineTotal;
  const vat = lineTotal - priceBeforeVat;
  const total = lineTotal;
  // upsert header
  const cols = ['receipt_no','receive_date','receipt_type','receive_status','receipt_status','note',
    'product_value','discount','vat_rate','price_before_vat','vat','total',
    'branch_code','branch_name','staff_recorder',
    'customer_name','customer_address','customer_phone','customer_id_card',
    'contract_no','contract_date','contract_ref','contract_status',
    'brand','model_series','model_code','product_code','color',
    'engine_no','chassis_no','plate_number','register_date','tax_paid_date',
    'entry_source','created_by','updated_at'];
  const vals = [
    esc(rno), d(h.receive_date), esc(h.receipt_type || 'จดทะเบียนใหม่'), esc(h.receive_status || 'ปกติ'), esc(h.receipt_status || 'ปกติ'), esc(h.note),
    num(lineTotal), num(h.discount || 0), num(vatRate), num(priceBeforeVat), num(vat), num(total),
    esc(h.branch_code), esc(h.branch_name), esc(h.staff_recorder),
    esc(h.customer_name), esc(h.customer_address), esc(h.customer_phone), esc(h.customer_id_card),
    esc(h.contract_no), d(h.contract_date), esc(h.contract_ref), esc(h.contract_status),
    esc(h.brand), esc(h.model_series), esc(h.model_code), esc(h.product_code), esc(h.color),
    esc(h.engine_no), esc(h.chassis_no), esc(h.plate_number), d(h.register_date), d(h.tax_paid_date),
    esc('manual'), esc(h.created_by || h.staff_recorder), 'NOW()'];
  const updateSet = cols.filter(c => c !== 'receipt_no' && c !== 'created_by').map((c,i) => `${c} = EXCLUDED.${c}`).join(', ');
  // sanitize line for SQL
  const lineValues = lines.map(ln => {
    const q = num(ln.qty || 1);
    const p = num(ln.price_before_discount ?? ln.price ?? 0);
    const dc = num(ln.discount || 0);
    const net = q * p - dc;
    return `(${esc(rno)}, ${esc(ln.income_type)}, ${esc(ln.income_code)}, ${esc(ln.income_name)}, ${esc(ln.description)}, ${num(q)}, ${num(p)}, ${num(dc)}, ${num(net)})`;
  }).join(',\n      ');
  query = `
    INSERT INTO registration_receipts (${cols.join(',')})
    VALUES (${vals.join(',')})
    ON CONFLICT (receipt_no) DO UPDATE SET ${updateSet};
    DELETE FROM registration_receipt_lines WHERE receipt_no = ${esc(rno)};
    INSERT INTO registration_receipt_lines (receipt_no, income_type, income_code, income_name, description, qty, price_before_discount, discount, net_price)
    VALUES
      ${lineValues};
    SELECT * FROM registration_receipts WHERE receipt_no = ${esc(rno)};`;
}
else if (action === 'delete_receipt') {
  const rno = String(body.receipt_no || '').trim();
  if (!rno) return [{ json: { query: "SELECT 'missing receipt_no' AS message" } }];
  // soft delete: status = cancelled
  query = `UPDATE registration_receipts SET receipt_status = 'ยกเลิก', updated_at = NOW()
    WHERE receipt_no = ${esc(rno)} RETURNING receipt_no, receipt_status;`;
}
else if (action === 'get_branches') {
  query = `SELECT DISTINCT branch_code, branch_name FROM registration_receipts
    WHERE branch_code IS NOT NULL AND branch_code <> ''
    ORDER BY branch_code;`;
}
else { query = "SELECT 'unknown action' AS message"; }
return [{ json: { query } }];
